import React, { useState } from 'react';
import { ethers } from 'ethers';
import { getContracts, getUser } from '../utils/web3';
import { uploadToIPFS, uploadMetadataToIPFS, createNFTMetadata, checkIPFSAvailability } from '../utils/ipfs';
import { storeFileLocally, createLocalMetadata, getLocalStorageInfo } from '../utils/localStorage';
import { storeFileReference, createCompactMetadata, getFileData } from '../utils/compactMetadata';

function MintForm() {
  const [nftType, setNftType] = useState('721');
  const [tokenName, setTokenName] = useState('');
  const [description, setDescription] = useState('');
  const [imageUrl, setImageUrl] = useState('');
  const [imageFile, setImageFile] = useState(null);
  const [imagePreview, setImagePreview] = useState('');
  const [mediaType, setMediaType] = useState('image');
  const [amount, setAmount] = useState('1');
  const [royalty, setRoyalty] = useState('10');
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState({ type: '', text: '' });

  const handleMediaUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      // Check file size based on type
      const maxSize = mediaType === 'video' ? 50 * 1024 * 1024 : 10 * 1024 * 1024; // 50MB for video, 10MB for audio/image
      
      if (file.size > maxSize) {
        setMessage({ 
          type: 'error', 
          text: `${mediaType === 'video' ? 'Video' : mediaType === 'audio' ? 'Audio' : 'Image'} size must be less than ${mediaType === 'video' ? '50MB' : '10MB'}` 
        });
        return;
      }
      
      // Check file type
      const validTypes = {
        image: ['image/jpeg', 'image/png', 'image/gif', 'image/webp'],
        audio: ['audio/mp3', 'audio/wav', 'audio/ogg', 'audio/m4a'],
        video: ['video/mp4', 'video/webm', 'video/ogg']
      };
      
      if (!validTypes[mediaType].includes(file.type)) {
        setMessage({ 
          type: 'error', 
          text: `Please upload a valid ${mediaType} file` 
        });
        return;
      }
      
      setImageFile(file);
      
      // Create preview
      const reader = new FileReader();
      reader.onloadend = () => {
        setImagePreview(reader.result);
        setImageUrl(reader.result);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleMint = async (e) => {
    e.preventDefault();
    
    if (!imageFile) {
      setMessage({ type: 'error', text: 'Please upload a media file' });
      return;
    }

    if (!tokenName || !description) {
      setMessage({ type: 'error', text: 'Please fill in all fields' });
      return;
    }

    setMessage({ type: 'warning', text: 'Starting minting process...' });
    setLoading(true);

    try {
      const { marketplace, erc721, erc1155 } = getContracts();
      const { address } = getUser();

      console.log('Contracts:', { marketplace, erc721, erc1155 });
      console.log('User address:', address);

      if (!erc721 || !erc1155 || !address) {
        throw new Error('Contracts or wallet not properly initialized. Please connect your wallet first.');
      }

      // Check IPFS availability first
      const ipfsAvailable = await checkIPFSAvailability();
      let tokenURI = '';
      
      if (ipfsAvailable) {
        setMessage({ type: 'warning', text: 'Uploading media to IPFS...' });
        
        try {
          // Upload media file to IPFS
          const mediaUploadResult = await uploadToIPFS(imageFile);
          
          if (!mediaUploadResult.success) {
            console.error('IPFS upload error details:', mediaUploadResult);
            const errorMsg = mediaUploadResult.error?.message || mediaUploadResult.error || 'Unknown error';
            throw new Error(`IPFS upload failed: ${errorMsg}`);
          }
          
          const mediaIpfsHash = mediaUploadResult.ipfsHash;
          const mediaUrl = `https://gateway.pinata.cloud/ipfs/${mediaIpfsHash}`;
          
          setMessage({ type: 'warning', text: 'Creating metadata...' });
          
          // Create metadata with IPFS media URL
          const metadata = createNFTMetadata(
            tokenName,
            description,
            mediaUrl,
            mediaType,
            address
          );
          
          setMessage({ type: 'warning', text: 'Uploading metadata to IPFS...' });
          
          // Upload metadata to IPFS
          const metadataUploadResult = await uploadMetadataToIPFS(metadata);
          
          if (!metadataUploadResult.success) {
            throw new Error(`Metadata upload failed: ${metadataUploadResult.error || 'Unknown error'}`);
          }
          
          const metadataIpfsHash = metadataUploadResult.ipfsHash;
          tokenURI = `https://gateway.pinata.cloud/ipfs/${metadataIpfsHash}`;
          
          setMessage({ type: 'success', text: 'Files uploaded to IPFS successfully!' });
        } catch (ipfsError) {
          console.error('IPFS upload failed:', ipfsError);
          setMessage({ type: 'warning', text: 'IPFS not available (free plan limit), using compact local storage...' });
          
          // Store file reference and create compact metadata
          const tokenId = Date.now().toString(); // Use timestamp as temporary token ID
          const fileReferenceResult = await storeFileReference(imageFile, tokenId);
          
          if (fileReferenceResult.success) {
            const compactMetadata = createCompactMetadata(
              tokenName,
              description,
              mediaType,
              address,
              tokenId
            );
            
            // Create compact metadata without embedding large files
            const metadataJson = JSON.stringify(compactMetadata);
            tokenURI = `data:application/json;base64,${btoa(metadataJson)}`;
            
            setMessage({ type: 'success', text: 'File stored efficiently. NFT will work on this device.' });
          } else {
            // Fallback to minimal metadata if file storage fails
            const fallbackMetadata = {
              name: tokenName,
              description: description,
              attributes: [
                {
                  trait_type: "Media Type",
                  value: mediaType
                },
                {
                  trait_type: "Creator",
                  value: address
                },
                {
                  trait_type: "Storage",
                  value: "Minimal"
                }
              ],
              created_at: new Date().toISOString()
            };
            
            const metadataJson = JSON.stringify(fallbackMetadata);
            tokenURI = `data:application/json;base64,${btoa(metadataJson)}`;
            
            setMessage({ type: 'warning', text: 'Using minimal metadata due to storage limitations.' });
          }
        }
      } else {
        setMessage({ type: 'warning', text: 'IPFS not available, using compact local storage...' });
        
        // Store file reference and create compact metadata
        const tokenId = Date.now().toString(); // Use timestamp as temporary token ID
        const fileReferenceResult = await storeFileReference(imageFile, tokenId);
        
        if (fileReferenceResult.success) {
          const compactMetadata = createCompactMetadata(
            tokenName,
            description,
            mediaType,
            address,
            tokenId
          );
          
          // Create compact metadata without embedding large files
          const metadataJson = JSON.stringify(compactMetadata);
          tokenURI = `data:application/json;base64,${btoa(metadataJson)}`;
          
          setMessage({ type: 'success', text: 'File stored efficiently. NFT will work on this device.' });
        } else {
          // Fallback to minimal metadata if file storage fails
          const fallbackMetadata = {
            name: tokenName,
            description: description,
            attributes: [
              {
                trait_type: "Media Type",
                value: mediaType
              },
              {
                trait_type: "Creator",
                value: address
              },
              {
                trait_type: "Storage",
                value: "Minimal"
              }
            ],
            created_at: new Date().toISOString()
          };
          
          const metadataJson = JSON.stringify(fallbackMetadata);
          tokenURI = `data:application/json;base64,${btoa(metadataJson)}`;
          
          setMessage({ type: 'warning', text: 'Using minimal metadata due to storage limitations.' });
        }
      }

      setMessage({ type: 'warning', text: 'Minting NFT...' });

      // Validate tokenURI is not empty
      if (!tokenURI || tokenURI.trim() === '') {
        throw new Error('Token URI is empty. Cannot mint NFT without metadata.');
      }

      console.log('Final tokenURI:', tokenURI);
      console.log('TokenURI length:', tokenURI.length);

      // Convert royalty percentage to basis points (multiply by 100) and ensure it's a number
      const royaltyBps = Math.floor(parseFloat(royalty) * 100);
      console.log('Royalty BPS:', royaltyBps, 'from royalty:', royalty);

      if (nftType === '721') {
        console.log('Minting ERC721 with params:', {
          to: address,
          tokenURI: tokenURI,
          royaltyRecipient: address,
          royaltyBps: royaltyBps
        });
        
        // Mint ERC721 with proper royalty formatting
        const tx = await erc721.safeMint(
          address,
          tokenURI,
          address,
          royaltyBps, // This should be a number, not BigInt
          {
            gasLimit: 300000, // Normal gas limit for compact metadata
            gasPrice: ethers.parseUnits('20', 'gwei') // Set higher gas price
          }
        );
        console.log('Transaction submitted:', tx.hash);
        await tx.wait();
        console.log('Transaction confirmed');
      } else {
        console.log('Minting ERC1155 with params:', {
          to: address,
          amount: parseInt(amount),
          tokenURI: tokenURI,
          royaltyRecipient: address,
          royaltyBps: royaltyBps
        });
        
        // Mint ERC1155 with proper royalty formatting
        const tx = await erc1155.mint(
          address,
          parseInt(amount),
          tokenURI,
          address,
          royaltyBps, // This should be a number, not BigInt
          "0x", // empty data parameter
          {
            gasLimit: 350000, // Normal gas limit for compact metadata
            gasPrice: ethers.parseUnits('20', 'gwei') // Set higher gas price
          }
        );
        console.log('Transaction submitted:', tx.hash);
        await tx.wait();
        console.log('Transaction confirmed');
      }

      setMessage({ 
        type: 'success', 
        text: 'NFT minted successfully! ' 
      });
      
      // Reset form
      setTokenName('');
      setDescription('');
      setImageUrl('');
      setImageFile(null);
      setImagePreview('');
      setMediaType('image');
      setAmount('1');
      setRoyalty('10');
      setNftType('721');
      
    } catch (error) {
      console.error('Minting error:', error);
      console.error('Error details:', {
        message: error.message,
        code: error.code,
        reason: error.reason,
        data: error.data,
        transaction: error.transaction
      });
      
      // Provide more specific error messages
      let errorMessage = 'Failed to mint NFT';
      
      if (error.message.includes('out of gas')) {
        errorMessage = 'Transaction failed: Gas limit too low. Try again with higher gas limit.';
      } else if (error.message.includes('insufficient funds')) {
        errorMessage = 'Insufficient funds for gas. Please add more ETH to your wallet.';
      } else if (error.message.includes('user rejected')) {
        errorMessage = 'Transaction was cancelled by user.';
      } else if (error.message.includes('network')) {
        errorMessage = 'Network error. Please check your connection and try again.';
      } else if (error.code === 4001) {
        errorMessage = 'Transaction was rejected by user.';
      } else if (error.message.includes('execution reverted')) {
        errorMessage = 'Transaction failed: Contract execution reverted. This might be due to invalid parameters or contract issues.';
      } else if (error.message.includes('Token URI is empty')) {
        errorMessage = 'Failed to create metadata. Please try again.';
      }
      
      setMessage({ 
        type: 'error', 
        text: errorMessage 
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="section">
      <h2 className="section-title">Mint New NFT</h2>
      
      <div className="form-group">
        <label>NFT Type</label>
        <select 
          value={nftType} 
          onChange={(e) => setNftType(e.target.value)}
        >
          <option value="721">ERC-721 (Unique)</option>
          <option value="1155">ERC-1155 (Multiple)</option>
        </select>
      </div>

      <div className="form-group">
        <label>Token Name *</label>
        <input 
          type="text" 
          value={tokenName}
          onChange={(e) => setTokenName(e.target.value)}
          placeholder="Enter NFT name"
        />
      </div>

      <div className="form-group">
        <label>Description *</label>
        <textarea 
          value={description}
          onChange={(e) => setDescription(e.target.value)}
          placeholder="Describe your NFT"
          rows="3"
        />
      </div>

      <div className="form-group">
        <label>Media Type</label>
        <select 
          value={mediaType} 
          onChange={(e) => setMediaType(e.target.value)}
        >
          <option value="image">🖼️ Image</option>
          <option value="audio">🎵 Audio/Music</option>
          <option value="video">🎬 Video</option>
        </select>
      </div>

      <div className="form-group">
        <label>Upload {mediaType === 'image' ? 'Image' : mediaType === 'audio' ? 'Audio' : 'Video'} *</label>
        <input 
          type="file" 
          accept={mediaType === 'image' ? 'image/*' : mediaType === 'audio' ? 'audio/*' : 'video/*'}
          onChange={handleMediaUpload}
          style={{ display: 'none' }}
          id="media-upload"
        />
        <label 
          htmlFor="media-upload"
          style={{
            display: 'block',
            padding: '12px',
            border: '2px dashed #00ff00',
            borderRadius: '8px',
            textAlign: 'center',
            cursor: 'pointer',
            backgroundColor: '#1a1a2e',
            color: '#00ff00'
          }}
        >
          {imageFile ? `Selected: ${imageFile.name}` : `Click to upload ${mediaType}`}
        </label>
        
        {imagePreview && (
          <div style={{ marginTop: '10px', textAlign: 'center' }}>
            {mediaType === 'image' ? (
              <img 
                src={imagePreview} 
                alt="Preview" 
                style={{ 
                  maxWidth: '200px', 
                  maxHeight: '200px', 
                  borderRadius: '8px',
                  border: '1px solid #00ff00'
                }} 
              />
            ) : mediaType === 'audio' ? (
              <audio controls style={{ maxWidth: '300px' }}>
                <source src={imagePreview} type={imageFile?.type} />
                Your browser does not support audio.
              </audio>
            ) : (
              <video controls style={{ maxWidth: '300px', maxHeight: '200px' }}>
                <source src={imagePreview} type={imageFile?.type} />
                Your browser does not support video.
              </video>
            )}
          </div>
        )}
        
        <small>
          {mediaType === 'image' && 'Supported formats: JPG, PNG, GIF, WebP. Max size: 10MB'}
          {mediaType === 'audio' && 'Supported formats: MP3, WAV, OGG, M4A. Max size: 10MB'}
          {mediaType === 'video' && 'Supported formats: MP4, WebM, OGG. Max size: 50MB'}
        </small>
      </div>

      {nftType === '1155' && (
        <div className="form-group">
          <label>Amount</label>
          <input 
            type="number" 
            value={amount}
            onChange={(e) => setAmount(e.target.value)}
            min="1"
            placeholder="Number of copies"
          />
        </div>
      )}

      <div className="form-group">
        <label>Royalty Percentage (%)</label>
        <input 
          type="number" 
          value={royalty}
          onChange={(e) => setRoyalty(e.target.value)}
          min="0"
          max="50"
          step="0.1"
          placeholder="e.g., 10 for 10%"
        />
        <small>Earn this percentage on secondary sales</small>
      </div>

      <button 
        className="submit-btn"
        onClick={handleMint}
        disabled={loading}
      >
        {loading ? 'Minting...' : 'Mint NFT'}
      </button>

      {message.text && (
        <div className={message.type}>
          {message.text}
        </div>
      )}

      <div style={{ marginTop: '20px', fontSize: '14px', color: '#aaa' }}>
        <strong>Note:</strong> For production, integrate with IPFS/Pinata to upload 
        images and metadata. Update the IPFS_CONFIG in utils/config.js with your Pinata keys.
      </div>
    </div>
  );
}

export default MintForm;
